  ONLY_COMPLETED_GENERATION_REQUESTS_CAN_BE_IMPORTED: "\u064a\u0645\u0643\u0646 \u0627\u0633\u062a\u064a\u0631\u0627\u062f \u0637\u0644\u0628\u0627\u062a \u0627\u0644\u062a\u0648\u0644\u064a\u062f \u0627\u0644\u0645\u0643\u062a\u0645\u0644\u0629 \u0641\u0642\u0637",
