  ONLY_PENDING_REVIEW_AI_QUESTIONS_CAN_BE_EDITED: "\u064a\u0645\u0643\u0646 \u062a\u0639\u062f\u064a\u0644 \u0623\u0633\u0626\u0644\u0629 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0627\u0644\u0645\u0639\u0644\u0651\u0642\u0629 \u0644\u0644\u0645\u0631\u0627\u062c\u0639\u0629 \u0641\u0642\u0637",
  ONLY_STUDENTS_CAN_BE_ENROLLED_IN_A_SUBJECT: "\u064a\u0645\u0643\u0646 \u062a\u0633\u062c\u064a\u0644 \u0627\u0644\u0637\u0644\u0627\u0628 \u0641\u0642\u0637 \u0641\u064a \u0627\u0644\u0645\u0627\u062f\u0629",
  ONLY_STUDENTS_ENROLLED_IN_THE_SUBJECT_CAN_TAKE_TESTS: "\u0641\u0642\u0637 \u0627\u0644\u0637\u0644\u0627\u0628 \u0627\u0644\u0645\u0633\u062c\u0651\u0644\u0648\u0646 \u0641\u064a \u0627\u0644\u0645\u0627\u062f\u0629 \u064a\u0645\u0643\u0646\u0647\u0645 \u0623\u062f\u0627\u0621 \u0627\u0644\u0627\u062e\u062a\u0628\u0627\u0631\u0627\u062a",
  ONLY_STUDENT_MEMBERSHIPS_ARE_ALLOWED_NOT_STUDENT_ROLE: "\u064a\u064f\u0633\u0645\u062d \u0641\u0642\u0637 \u0628\u0639\u0636\u0648\u064a\u0627\u062a STUDENT: {not_student_role}",
  ONLY_SUBJECT_TEACHERS_OR_WORKSPACE_ADMINS_CAN_MANAGE_STUDENT_GROUPS: "\u0641\u0642\u0637 \u0645\u0639\u0644\u0645\u0648 \u0627\u0644\u0645\u0627\u062f\u0629 \u0623\u0648 \u0645\u0634\u0631\u0641\u0648 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647\u0645 \u0625\u062f\u0627\u0631\u0629 \u0645\u062c\u0645\u0648\u0639\u0627\u062a \u0627\u0644\u0637\u0644\u0627\u0628",
  ONLY_THE_CREATOR_OR_WORKSPACE_ADMIN_CAN_DELETE_THIS_BANK: "\u0641\u0642\u0637 \u0627\u0644\u0645\u064f\u0646\u0634\u0626 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062d\u0630\u0641 \u0628\u0646\u0643 \u0627\u0644\u0623\u0633\u0626\u0644\u0629 \u0647\u0630\u0627",
  ONLY_THE_CREATOR_OR_WORKSPACE_ADMIN_CAN_UPDATE_THIS_BANK: "\u0641\u0642\u0637 \u0627\u0644\u0645\u064f\u0646\u0634\u0626 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062a\u062d\u062f\u064a\u062b \u0628\u0646\u0643 \u0627\u0644\u0623\u0633\u0626\u0644\u0629 \u0647\u0630\u0627",
  ONLY_THE_INSTITUTION_OWNER_OR_WORKSPACE_ADMIN_CAN_LIST_WORKSPACE_MEMBERS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0627\u0644\u0645\u0624\u0633\u0633\u0629 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0639\u0631\u0636 \u0623\u0639\u0636\u0627\u0621 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644",
  ONLY_THE_TEST_CREATOR_CAN_DELETE_THIS_TEST: "\u0641\u0642\u0637 \u0645\u064f\u0646\u0634\u0626 \u0627\u0644\u0627\u062e\u062a\u0628\u0627\u0631 \u064a\u0645\u0643\u0646\u0647 \u062d\u0630\u0641 \u0647\u0630\u0627 \u0627\u0644\u0627\u062e\u062a\u0628\u0627\u0631",
  ONLY_THE_WORKSPACE_OWNER_CAN_DELETE_THIS_WORKSPACE: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062d\u0630\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u0647\u0630\u0647",
  ONLY_THE_WORKSPACE_OWNER_OR_ADMIN_CAN_LIST_STUDENTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0639\u0631\u0636 \u0627\u0644\u0637\u0644\u0627\u0628",
  ONLY_THE_WORKSPACE_OWNER_OR_ADMIN_CAN_MANAGE_WORKSPACE_MEMBERS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0625\u062f\u0627\u0631\u0629 \u0623\u0639\u0636\u0627\u0621 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_ARCHIVE_SUBJECTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0623\u0631\u0634\u0641\u0629 \u0627\u0644\u0645\u0648\u0627\u062f",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_ASSIGN_SUBJECTS_TO_STUDENTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0648\u0627\u062f \u0644\u0644\u0637\u0644\u0627\u0628",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_ASSIGN_TEACHERS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062a\u0639\u064a\u064a\u0646 \u0627\u0644\u0645\u0639\u0644\u0645\u064a\u0646",
