  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_MANAGE_TOPICS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0625\u062f\u0627\u0631\u0629 \u0627\u0644\u0645\u0648\u0627\u0636\u064a\u0639",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_REMOVE_STUDENT_SUBJECT_ASSIGNMENTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0625\u0632\u0627\u0644\u0629 \u062a\u0639\u064a\u064a\u0646\u0627\u062a \u0645\u0648\u0627\u062f \u0627\u0644\u0637\u0627\u0644\u0628",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_REMOVE_TEACHERS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u0625\u0632\u0627\u0644\u0629 \u0627\u0644\u0645\u0639\u0644\u0645\u064a\u0646",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_UPDATE_STUDENT_SUBJECT_ASSIGNMENTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062a\u062d\u062f\u064a\u062b \u062a\u0639\u064a\u064a\u0646\u0627\u062a \u0645\u0648\u0627\u062f \u0627\u0644\u0637\u0627\u0644\u0628",
  ONLY_WORKSPACE_OWNER_OR_ADMIN_CAN_UPDATE_SUBJECTS: "\u0641\u0642\u0637 \u0645\u0627\u0644\u0643 \u0623\u0648 \u0645\u0634\u0631\u0641 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646\u0647 \u062a\u062d\u062f\u064a\u062b \u0627\u0644\u0645\u0648\u0627\u062f",
  ONLY_WORKSPACE_TEACHERS_OR_ADMINS_CAN_BE_ASSIGNED_AS_SUBJECT_TEACHERS: "\u0641\u0642\u0637 \u0645\u0639\u0644\u0645\u0648 \u0623\u0648 \u0645\u0634\u0631\u0641\u0648 \u0645\u0633\u0627\u062d\u0629 \u0627\u0644\u0639\u0645\u0644 \u064a\u0645\u0643\u0646 \u062a\u0639\u064a\u064a\u0646\u0647\u0645 \u0643\u0645\u0639\u0644\u0645\u064a \u0645\u0627\u062f\u0629",
  OPENROUTER_API_KEY_IS_REQUIRED_WHEN_AI_QUESTION_PROVIDER_OPENROUTER: "\u0645\u0641\u062a\u0627\u062d OPENROUTER_API_KEY \u0645\u0637\u0644\u0648\u0628 \u0639\u0646\u062f\u0645\u0627 \u064a\u0643\u0648\u0646 AI_QUESTION_PROVIDER=openrouter",
  OPENROUTER_ERROR_402_INSUFFICIENT_CREDITS_FOR_THIS_MODEL: "\u062e\u0637\u0623 OpenRouter (402): \u0631\u0635\u064a\u062f \u063a\u064a\u0631 \u0643\u0627\u0641\u064d \u0644\u0647\u0630\u0627 \u0627\u0644\u0646\u0645\u0648\u0630\u062c.",
  OPENROUTER_INSUFFICIENT_CREDITS: "\u062e\u0637\u0623 OpenRouter (402): \u0631\u0635\u064a\u062f \u063a\u064a\u0631 \u0643\u0627\u0641\u064d \u0644\u0647\u0630\u0627 \u0627\u0644\u0646\u0645\u0648\u0630\u062c. \u0627\u0633\u062a\u062e\u062f\u0645 \u0646\u0645\u0648\u0630\u062c\u064b\u0627 \u0645\u062c\u0627\u0646\u064a\u064b\u0627 (\u0639\u064a\u0651\u0646 OPENROUTER_MODEL \u0625\u0644\u0649 \u0646\u0645\u0648\u0630\u062c ':free' \u0645\u062b\u0644 'meta-llama/llama-3.3-70b-instruct:free')\u060c \u0623\u0648 \u0642\u0644\u0651\u0644 AI_MAX_OUTPUT_TOKENS\u060c \u0623\u0648 \u0623\u0636\u0641 \u0631\u0635\u064a\u062f\u064b\u0627 \u0639\u0644\u0649 https://openrouter.ai/settings/credits.",
  ORGANIZATION_IS_ALREADY_SUSPENDED: "\u0627\u0644\u0645\u0624\u0633\u0633\u0629 \u0645\u0648\u0642\u0648\u0641\u0629 \u0628\u0627\u0644\u0641\u0639\u0644",
  ORGANIZATION_IS_NOT_SUSPENDED: "\u0627\u0644\u0645\u0624\u0633\u0633\u0629 \u063a\u064a\u0631 \u0645\u0648\u0642\u0648\u0641\u0629",
  ORGANIZATION_NOT_FOUND: "\u0644\u0645 \u064a\u062a\u0645 \u0627\u0644\u0639\u062b\u0648\u0631 \u0639\u0644\u0649 \u0627\u0644\u0645\u0624\u0633\u0633\u0629",
  ORGANIZATION_RESTORED_SUCCESSFULLY: "\u062a\u0645\u062a \u0627\u0633\u062a\u0639\u0627\u062f\u0629 \u0627\u0644\u0645\u0624\u0633\u0633\u0629 \u0628\u0646\u062c\u0627\u062d",
  ORGANIZATION_SUSPENDED_SUCCESSFULLY: "\u062a\u0645 \u0625\u064a\u0642\u0627\u0641 \u0627\u0644\u0645\u0624\u0633\u0633\u0629 \u0628\u0646\u062c\u0627\u062d",
  OTP_RESEND_LIMIT_REACHED_TRY_AGAIN_LATER: "\u062a\u0645 \u0627\u0644\u0648\u0635\u0648\u0644 \u0625\u0644\u0649 \u062d\u062f \u0625\u0639\u0627\u062f\u0629 \u0625\u0631\u0633\u0627\u0644 \u0631\u0645\u0632 OTP. \u062d\u0627\u0648\u0644 \u0644\u0627\u062d\u0642\u064b\u0627.",
  OTP_VERIFIED_SET_YOUR_NEW_PASSWORD_VIA_POST_AUTH_RESET_PASSWORD: "\u062a\u0645 \u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0631\u0645\u0632 OTP. \u0639\u064a\u0651\u0646 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631 \u0627\u0644\u062c\u062f\u064a\u062f\u0629 \u0639\u0628\u0631 POST /auth/reset-password.",
