  PASSWORD_RESET_OTP_NOT_VERIFIED_CALL_POST_AUTH_VERIFY_OTP_FIRST: "\u0644\u0645 \u064a\u062a\u0645 \u0627\u0644\u062a\u062d\u0642\u0642 \u0645\u0646 \u0631\u0645\u0632 OTP \u0644\u0625\u0639\u0627\u062f\u0629 \u062a\u0639\u064a\u064a\u0646 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631. \u0627\u0633\u062a\u062f\u0639\u0650 POST /auth/verify-otp \u0623\u0648\u0644\u0627\u064b.",
  PASSWORD_RESET_SUCCESSFUL: "\u062a\u0645\u062a \u0625\u0639\u0627\u062f\u0629 \u062a\u0639\u064a\u064a\u0646 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631 \u0628\u0646\u062c\u0627\u062d",
