  PLEASE_WAIT_WAIT_SECOND_S_BEFORE_REQUESTING_ANOTHER_OTP: "\u064a\u0631\u062c\u0649 \u0627\u0644\u0627\u0646\u062a\u0638\u0627\u0631 {wait} \u062b\u0627\u0646\u064a\u0629 \u0642\u0628\u0644 \u0637\u0644\u0628 \u0631\u0645\u0632 OTP \u0622\u062e\u0631",
