const source = JSON.parse(fs.readFileSync(SOURCE, "utf8"));
const codes = Object.keys(source);

const en = {};
const ar = {};
const missingAr = [];
const seenMessages = new Set();

for (const code of codes) {
  const message = source[code].message;
  seenMessages.add(message);
  en[message] = message;
  if (!(code in AR)) {
    missingAr.push(code);
    continue;
  }
  ar[message] = AR[code];
}

fs.mkdirSync(path.dirname(OUT_EN), { recursive: true });
fs.mkdirSync(path.dirname(OUT_AR), { recursive: true });
fs.writeFileSync(OUT_EN, JSON.stringify(en, null, 2) + "\n", "utf8");
fs.writeFileSync(OUT_AR, JSON.stringify(ar, null, 2) + "\n", "utf8");

// -------- verification --------
const errors = [];
const enKeys = Object.keys(en);
const arKeys = Object.keys(ar);

if (missingAr.length) errors.push("Missing AR translations for codes: " + missingAr.join(", "));
if (enKeys.length !== arKeys.length) errors.push(`Key count mismatch: en=${enKeys.length} ar=${arKeys.length}`);

for (const k of enKeys) {
  if (en[k] !== k) errors.push(`en value != key for: ${k}`);
}
for (const k of arKeys) {
  if (!(k in en)) errors.push(`ar key not in en: ${k}`);
}
for (const code of codes) {
  const message = source[code].message;
  if (!(message in en)) errors.push(`source message not in en: ${message}`);
  if (!(message in ar)) errors.push(`source message not in ar: ${message}`);
}

// placeholder preservation check
const placeholderRe = /\{[^}]+\}/g;
for (const code of codes) {
  const message = source[code].message;
  if (!(message in ar)) continue;
  const enPh = (message.match(placeholderRe) || []).sort();
  const arPh = (ar[message].match(placeholderRe) || []).sort();
  if (JSON.stringify(enPh) !== JSON.stringify(arPh)) {
    errors.push(`placeholder mismatch for [${code}] en=${JSON.stringify(enPh)} ar=${JSON.stringify(arPh)}`);
  }
}

console.log("Source codes:            ", codes.length);
console.log("Unique source messages:  ", seenMessages.size);
console.log("en keys:                 ", enKeys.length);
console.log("ar keys:                 ", arKeys.length);

if (errors.length) {
  console.error("\nVERIFICATION FAILED:");
  for (const e of errors) console.error(" - " + e);
  process.exit(1);
} else {
  console.log("\nVERIFICATION PASSED: en and ar are complete, keys match, identity map valid, placeholders preserved.");
}
